import { useEffect, useState } from "react";
import { shaderContainer, shaderVisible } from "./WaterShader.css.ts";

function getBackdropUrl(): string {
  const isDark =
    document.documentElement.getAttribute("data-theme") === "dark";
  const isDesktop = window.innerWidth >= 1024;

  if (isDark) return isDesktop ? "/night-backdrop.svg" : "/mobile_night.svg";
  return isDesktop ? "/beach_backdrop.svg" : "/mobile_backdrop.svg";
}

export default function WaterShader() {
  const [visible, setVisible] = useState(false);
  const [backdropUrl, setBackdropUrl] = useState<string | undefined>(undefined);

  useEffect(() => {
    setBackdropUrl(getBackdropUrl());

    const onResize = () => setBackdropUrl(getBackdropUrl());
    window.addEventListener("resize", onResize);

    const observer = new MutationObserver(() => setBackdropUrl(getBackdropUrl()));
    observer.observe(document.documentElement, {
      attributes: true,
      attributeFilter: ["data-theme"],
    });

    const id = requestAnimationFrame(() => setVisible(true));
    return () => {
      cancelAnimationFrame(id);
      window.removeEventListener("resize", onResize);
      observer.disconnect();
    };
  }, []);

  return (
    <div
      className={`${shaderContainer}${visible ? ` ${shaderVisible}` : ""}`}
      aria-hidden="true"
    >
      <Water
        speed={0.54}
        colorBack="#00000000"
        colorHighlight="#ffffff"
        size={0.74}
        highlights={0.07}
        layering={0.5}
        edges={0.8}
        waves={0.5}
        caustic={0.1}
        image={backdropUrl}
        scale={1.43}
        fit="contain"
        style={{ width: "100%", height: "100%" }}
