      className={`${shaderContainer}${visible ? ` ${shaderVisible}` : ""}`}
      aria-hidden="true"
    >
      <Water
        speed={0.54}
        colorBack="#00000000"
        colorHighlight="#ffffff"
        size={0.74}
        highlights={0.07}
        layering={0.5}
        edges={0.8}
        waves={0.5}
        caustic={0.1}
        image={backdropUrl}
        scale={1.43}
        fit="contain"
        style={{ width: "100%", height: "100%" }}
      />
    </div>
  );
}

